// Extract and merge JSON from Code Node output
const jsonData = $input.all().map(item => item.json);

// Function to format structured text for Google Docs
function formatContent(data) {
    let content = `# Research\n\n`;

    data.forEach(section => {
        content += `## ${section.section}\n`;

        // Loop through all keys except 'section'
        Object.keys(section).forEach(key => {
            if (key !== "section") {
                if (Array.isArray(section[key])) {
                    content += `- **${key.replace(/_/g, " ")}**:\n  - ` + section[key].join("\n  - ") + `\n\n`;
                } else {
                    content += `- **${key.replace(/_/g, " ")}**: ${section[key]}\n\n`;
                }
            }
        });
    });

    return content.trim();
}

// Generate the formatted text output
const documentText = formatContent(jsonData);

// Return structured text for Google Docs
return [{
    json: {
        document_name: "Research",
        content: documentText // This ensures 'content' is always returned
    }
}];

// Access all input items (each one is a video)
const items = $input.all();

// For each video item, join the captions from data[]
const result = items.map(item => {
  const data = item.json.data;

  // Safely join text only if data is an array
  const fullCaption = Array.isArray(data)
    ? data.map(d => d.text).join(' ')
    : '';

  // Truncate to 1500 characters to stay within token limits
  const truncated = fullCaption.substring(0, 1500);

  return {
    json: {
      full_caption: truncated
    }
  };
});

return result;

const items = $input.all();

// Pick the longest post as the best one
let bestOutput = '';
items.forEach(item => {
  const output = item.json.output || '';
  if (output.length > bestOutput.length) {
    bestOutput = output;
  }
});

const raw = bestOutput;

const cleanedLines = raw
  .split('\n')
  .map(line => {
    const trimmed = line.trim();
    if (/^#+\s*(linkedin content|undefined)?$/i.test(trimmed)) return '';
    if (/^- \*\*.*\*\*:\s*#/.test(trimmed)) return '';
    if (/^#+\s*$/.test(trimmed)) return '';
    const headerMatch = trimmed.match(/^#+\s*(.+)/);
    if (headerMatch) {
      return headerMatch[1].trim();
    }
    return trimmed;
  });

let finalOutput = '';
for (let i = 0; i < cleanedLines.length; i++) {
  const line = cleanedLines[i];
  if (line === '') {
    finalOutput += '\n\n';
  } else {
    finalOutput += line + '\n';
  }
}

return [{
  json: {
    linkedin_post: finalOutput.trim()
  }
}];

const linkedin = $('Linkedin formatted output1').first().json.linkedin_post || "";
const twitter = $('Twitter/X agent').first().json.output || "";
const facebook = $('Facebook agent').first().json.output || "";
const instagram = $('Instagram agent').first().json.output || "";
const imageUrl = $('Extract Image URL').first().json.image_url || "";
const photographer = $('Extract Image URL').first().json.photographer || "";
const pexelsLink = $('Extract Image URL').first().json.pexels_link || "";

const imageSection = imageUrl
  ? "SUGGESTED IMAGE\n=============\nURL: " + imageUrl + "\nPhoto by: " + photographer + "\nSource: " + pexelsLink
  : "SUGGESTED IMAGE\n=============\nNo image found";

const combined = [
  "LINKEDIN POST", "============", linkedin, "",
  "TWITTER/X THREAD", "================", twitter, "",
  "FACEBOOK POST", "=============", facebook, "",
  "INSTAGRAM CAPTION", "=================", instagram, "",
  imageSection
].join("\n");

return [{ json: { combined_posts: combined, linkedin_post: linkedin } }];

